mapper.insert:

    SELECT SQ_HIST_SEQ.NEXTVAL FROM DUAL

INSERT INTO MCP_NICE_HIST (
      NICE_HIST_SEQ            --PK
    , REQ_SEQ                  --일련번호 기본키
    , RES_SEQ                  --요청 일련번호
    , AUTH_TYPE                 --요청 구분
    , NAME                     --인증성명
    , BIRTH_DATE               --인증생년월일
    , GENDER                   --GENDER
    , NATIONAL_INFO            --NATIONAL_INFO
    , DUP_INFO                 --DUP_INFO
    , CONN_INFO                --CONN_INFO
    , PARAM_R1                 --파라메터 1
    , PARAM_R2                 --파라메터 2
    , PARAM_R3                 --파라메터 3
    , END_YN                   --종료여부
    , N_REFERER                --referer
    , RIP                      --등록아이피
    , SYS_RDATE_DT             --등록일
    , SYS_RDATE                --등록일시
    , RVISN_DTTM               --수정일
    , COMPL_DTTM               --인증 완료시
    , MOBILE_CO                -- 이동사구분(모바일 인증)
    , MOBILE_NO                -- 휴대폰 번호(모바일 인증)
) VALUES (
    #{niceHistSeq}
    , #{reqSeq}
    , #{resSeq}
    , #{authType}
    , #{name}
    , #{birthDate}
    , #{gender}
    , #{nationalInfo}
    , #{dupInfo}
    , #{connInfo}
    , #{paramR1}
    , #{paramR2}
    , #{paramR3}
    , 'N'
    , #{nReferer}
    , #{rip}
    , TO_CHAR(SYSDATE, 'YYYYMMDD')


            , #{sysRdate}


            , SYSDATE


    , SYSDATE
    , SYSDATE
    , #{sMobileCo}
    , #{sMobileNo}
)

mapper.update:
UPDATE MCP_NICE_HIST SET
     RVISN_DTTM = SYSDATE                                      --수정일

       , REQ_SEQ = #{reqSeq}                                            --일련번호 기본키


       , RES_SEQ = #{resSeq}                                            --요청 일련번호


       , AUTH_TYPE = #{authType}                                          --요청 구분


      , GENDER = #{gender}                                             --GENDER


       , NATIONAL_INFO = #{nationalInfo}                                --NATIONAL_INFO


       , DUP_INFO = #{dupInfo}                                          --DUP_INFO


       , CONN_INFO = #{connInfo}                                        --CONN_INFO


        , END_YN = #{endYn}                                              --종료여부


        , COMPL_DTTM = SYSDATE                                           --인증 완료시간


        , NAME = #{toName}


        , BIRTH_DATE = #{toBirthDate}


        , PARAM_R3 = #{paramR3}


        , SYS_RDATE = #{sysRdate}


        , N_REFERER = #{nReferer}

WHERE 1=1

        AND NICE_HIST_SEQ = #{niceHistSeq}


        AND NAME = #{name}


        AND BIRTH_DATE = #{birthDate}
        AND END_YN = 'N' --활성화 상태만..


        AND PARAM_R3 = #{paramR3}

mapper.select:
SELECT NICE_HIST_SEQ , REQ_SEQ , RES_SEQ , AUTH_TYPE , NAME , BIRTH_DATE , GENDER , NATIONAL_INFO , DUP_INFO , CONN_INFO , PARAM_R1 , PARAM_R2 , PARAM_R3 , END_YN , N_REFERER , RIP , SYS_RDATE_DT , SYS_RDATE , RVISN_DTTM FROM ( SELECT NICE_HIST_SEQ , REQ_SEQ , RES_SEQ , AUTH_TYPE , NAME , BIRTH_DATE , GENDER , NATIONAL_INFO , DUP_INFO , CONN_INFO , PARAM_R1 , PARAM_R2 , PARAM_R3 , END_YN , N_REFERER , RIP , SYS_RDATE_DT , SYS_RDATE , RVISN_DTTM FROM MCP_NICE_HIST WHERE 1=1
AND NICE_HIST_SEQ = #{niceHistSeq}
AND NAME = #{name}
AND BIRTH_DATE = #{birthDate}
AND END_YN = #{endYn}
AND PARAM_R3 = #{paramR3}
AND RES_SEQ = #{resSeq}
AND SYS_RDATE >= (SYSDATE-1/24) -- 1시간 전 DATA만 유효 ORDER BY SYS_RDATE DESC ) WHERE ROWNUM =1

SELECT COUNT(*)
  FROM NMCP_SELF_SMS_AUTH
 WHERE REQUEST_KEY = #{requestKey}

