INSERT INTO NMCP_SELF_SMS_AUTH (
      SELF_SMS_AUTH_SEQ        /*PK*/
    , REQUEST_KEY			   /*REQUEST_KEY*/
    , REQ_SEQ                  /*일련번호 기본키*/
    , RES_SEQ                  /*요청 일련번호*/
    , AUTH_TYPE                /*요청 구분*/
    , NAME                     /*인증성명*/
    , BIRTH_DATE               /*인증생년월일*/
    , GENDER                   /*GENDER*/
    , NATIONAL_INFO            /*NATIONAL_INFO*/
    , DUP_INFO                 /*DUP_INFO*/
    , CONN_INFO                /*CONN_INFO*/
    , PARAM_R3                 /*smsAuth*/
    , N_REFERER                /*referer*/
    , RIP                      /*등록아이피*/
    , MOBILE_NO                /*인증휴대폰번호*/
    , MOBILE_CO                /*인증휴대폰통신사*/
    , AUTH_TIME                /*인증시간*/
) VALUES (
    #{selfSmsAuthSeq}
    , #{requestKey}
    , #{reqSeq}
    , #{resSeq}
    , #{authType}
    , #{name}
    , #{birthDate}
    , #{gender}
    , #{nationalInfo}
    , #{dupInfo}
    , #{connInfo}
    , #{paramR3}
    , #{nReferer}
    , #{rip}
    , #{sMobileNo}
    , #{sMobileCo}


            , #{sysRdate}


            , SYSDATE


)


    SELECT SQ_NICE_TRY_HIST_SEQ.NEXTVAL FROM DUAL

INSERT INTO MCP_NICE_TRY_HIST (
      NICE_TRY_HIST_SEQ       /*순번 (PK)*/
    , REQ_SEQ                 /*요청 일련번호*/
    , RES_SEQ                 /*응답 일련번호*/
    , AUTH_TYPE               /*본인인증 유형 (N: 네이버인증서, A:패스인증서, T: 토스인증서)*/
    , NAME                    /*인증성명*/
    , BIRTH_DATE              /*인증 생년월일*/
    , CONN_INFO               /*CID*/
    , N_REFERER               /*REFERER*/
    , RIP                     /*IP*/
    , SYS_RDATE_DT            /*생성일*/
    , SYS_RDATE               /*인증 시작 일시*/
    , SUCC_YN                 /*성공,실패여부*/
    , FNL_SUCC_YN             /*최종 성공,실패 여부 (본인인증에 사용한 정보와 고객정보 일치 여부)*/
) VALUES (
      #{niceTryHistSeq}
    , #{reqSeq}
    , #{resSeq}
    , #{authType}
    , #{name}
    , #{birthDate}
    , #{connInfo}
    , #{nReferer}
    , #{rip}
    , TO_CHAR(SYSDATE, 'YYYYMMDD')


            , #{sysRdate}


            , SYSDATE


    , #{succYn}
    , 'N'
)

