UPDATE MCP_NICE_TRY_HIST SET
    RVISN_DTTM = SYSDATE

    , REQ_SEQ = #{reqSeq}


    , RES_SEQ = #{resSeq}


    , NAME = #{name}


    , BIRTH_DATE = #{birthDate}


    , CONN_INFO = #{connInfo}


    , N_REFERER = #{nReferer}


    , SYS_RDATE = #{sysRdate}


    , FNL_SUCC_YN = #{fnlSuccYn}

WHERE 1=1
AND NICE_TRY_HIST_SEQ = #{niceTryHistSeq}
